const trigger = label.v;
let action = '';
let data = null;
let timestamp = null;

if (trigger && typeof trigger === 'object' && typeof trigger.action === 'string') {
  action = trigger.action || '';
  data = trigger.data || null;
  timestamp = trigger.timestamp || null;
} else {
  const a = ctx.getLabel({ model_id: 100, p: 1, r: 0, c: 0, k: 'action' });
  action = typeof a === 'string' ? a : '';
  data = ctx.getLabel({ model_id: 100, p: 1, r: 0, c: 0, k: 'data' });
  timestamp = ctx.getLabel({ model_id: 100, p: 1, r: 0, c: 0, k: 'timestamp' });
}

if (action === 'submit') {
  const color = '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0');
  const patch = {
    version: 'mt.v0',
    op_id: 'color_response_' + Date.now(),
    records: [{
      op: 'add_label', model_id: 100, p: 0, r: 0, c: 0,
      k: 'bg_color', t: 'str', v: color
    }, {
      op: 'add_label', model_id: 100, p: 0, r: 0, c: 0,
      k: 'status', t: 'str', v: 'color_updated_' + color
    }]
  };
  ctx.writeLabel({ model_id: 100, p: 0, r: 0, c: 0, k: 'bg_color' }, 'str', color);
  ctx.writeLabel({ model_id: 100, p: 0, r: 0, c: 0, k: 'status' }, 'str', 'processed');
  return patch;
}
